BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name ?ownerName ?ownerType ?childName ?childType WHERE {
  {
    ?elem vocab:NamedElement_name "Alignment%20and%20Phasing%20System" .
    ?elem rdf:type vocab:package .
    ?elem rdf:type ?type .
    OPTIONAL {
      ?elem vocab:Element_owner ?owner .
      ?owner vocab:NamedElement_name ?ownerName .
      ?owner rdf:type ?ownerType .
    }
    OPTIONAL {
      ?elem vocab:Element_ownedElement ?child .
      ?child vocab:NamedElement_name ?childName .
      ?child rdf:type ?childType .
    }
  }
}
LIMIT 25

